@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_102ad492faf7439d87478c1ad78745b4.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<div class="chat-container">
    @* ── Left sidebar: channel list ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h2>Channels</h2>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var ch in _channels)
                {
                    <li class="channel-item @(ch.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-name"># @ch.Name</div>
                        <div class="channel-desc">@Truncate(ch.Description, 40)</div>
                        @if (ch.UnreadCount > 0)
                        {
                            <span class="unread-badge">@ch.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h3># @_activeChannel.Name</h3>
                <span class="header-desc">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_hasMoreMessages)
                {
                    <button class="load-more-btn" @onclick="LoadOlderMessagesAsync" disabled="@_loadingOlder">
                        ↑ Load older messages
                    </button>
                }

                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-bubble @(msg.ReplyToId is not null ? "is-reply" : "")"
                             @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => { if (_hoveredMessageId == msg.Id) _hoveredMessageId = null; }">
                            <div class="message-top-row">
                                <span class="msg-author">@msg.Author</span>
                                <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="msg-content">@msg.Content</div>

                            @* Reactions *@
                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reactions-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" @onclick="() => ToggleReactionAsync(msg.Id, r.Emoji)"
                                                title="@string.Join(", ", r.Users)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread starter indicator *@
                            @if (GetReplyCount(msg.Id) > 0)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    💬 @GetReplyCount(msg.Id) replies
                                </button>
                            }

                            @* Hover actions *@
                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" @onclick="() => OpenThreadAsync(msg)" title="Reply in thread">
                                        💬 Reply
                                    </button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" @onclick="() => ToggleEmojiPicker(msg.Id)" title="Add reaction">
                                            😀 React
                                        </button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="emoji-option" @onclick="() => AddReactionFromPickerAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_newMessageText" @bind:event="oninput"
                          @onkeydown="HandleMainKeyDown"
                          placeholder="Message #@_activeChannel.Name" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMainMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start messaging</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread">✕</button>
            </div>
            <div class="thread-root-quote">
                <span class="msg-author">@_threadRootMessage.Author</span>
                <span class="msg-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <div class="msg-content">@_threadRootMessage.Content</div>
            </div>

            <div class="thread-replies">
                @if (_threadMessages is not null)
                {
                    @foreach (var reply in _threadMessages)
                    {
                        <div class="message-bubble thread-reply">
                            <div class="message-top-row">
                                <span class="msg-author">@reply.Author</span>
                                <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="msg-content">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reactions-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" @onclick="() => ToggleReactionAsync(reply.Id, r.Emoji)"
                                                title="@string.Join(", ", r.Users)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="thread-input-area">
                <textarea @bind="_threadReplyText" @bind:event="oninput"
                          @onkeydown="HandleThreadKeyDown"
                          placeholder="Reply…" rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync" disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;

    private List<Message>? _messages;
    private int _skip;
    private bool _hasMoreMessages = true;
    private bool _loadingOlder;

    private string _newMessageText = "";

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;
    private string _threadReplyText = "";

    // Hover / emoji picker state
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    private ElementReference _messageListRef;

    // Reply counts keyed by root message id
    private readonly Dictionary<int, int> _replyCounts = new();

    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messages = null;
        _skip = 0;
        _hasMoreMessages = true;
        _replyCounts.Clear();

        CloseThread();

        var msgs = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = msgs;
        _skip = msgs.Count;
        _hasMoreMessages = msgs.Count >= PageSize;

        BuildReplyCounts();

        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channels to update unread badge
        _channels = await ChatService.GetChannelsAsync();
    }

    // ── Message loading & sending ──

    private async Task LoadOlderMessagesAsync()
    {
        if (_activeChannelId is null || _loadingOlder) return;

        _loadingOlder = true;
        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count > 0)
        {
            _messages = [..older, ..(_messages ?? [])];
            _skip += older.Count;
            BuildReplyCounts();
        }
        _hasMoreMessages = older.Count >= PageSize;
        _loadingOlder = false;
    }

    private async Task SendMainMessageAsync()
    {
        if (_activeChannelId is null || string.IsNullOrWhiteSpace(_newMessageText)) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages ??= [];
        _messages.Add(sent);
        _newMessageText = "";

        await ScrollToBottomAsync();
    }

    private async Task HandleMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMainMessageAsync();
        }
    }

    // ── Thread ──

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadReplyText = "";
        _threadOpen = true;
        _emojiPickerMessageId = null;

        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
        _threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (_threadRootMessage is null || string.IsNullOrWhiteSpace(_threadReplyText)) return;
        if (_activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadMessages ??= [];
        _threadMessages.Add(reply);
        _threadReplyText = "";

        // Update reply count in main view
        _replyCounts[_threadRootMessage.Id] = _threadMessages.Count;
    }

    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Reactions ──

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionFromPickerAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await ToggleReactionAsync(messageId, emoji);
    }

    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh messages to reflect new reaction state
        if (_activeChannelId is not null && _messages is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _skip > 0 ? _skip : PageSize);
            _messages = refreshed;
            _skip = refreshed.Count;
            BuildReplyCounts();
        }

        // Also refresh thread if open
        if (_threadRootMessage is not null)
        {
            _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    // ── Helpers ──

    private void BuildReplyCounts()
    {
        if (_messages is null) return;
        _replyCounts.Clear();
        foreach (var msg in _messages.Where(m => m.ReplyToId is not null))
        {
            var rootId = msg.ReplyToId!.Value;
            _replyCounts[rootId] = _replyCounts.GetValueOrDefault(rootId) + 1;
        }
    }

    private int GetReplyCount(int messageId) => _replyCounts.GetValueOrDefault(messageId);

    private static string Truncate(string text, int maxLen) =>
        text.Length <= maxLen ? text : string.Concat(text.AsSpan(0, maxLen), "…");

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private async Task ScrollToBottomAsync()
    {
        try
        {
            await JS.InvokeVoidAsync("eval", "document.querySelector('.message-list')?.scrollTo(0, document.querySelector('.message-list')?.scrollHeight)");
        }
        catch
        {
            // Ignore JS interop errors during prerender
        }
    }
}

