    height: 100vh;
    width: 100vw;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    color: #1d1c1d;
    background: #fff;
}

/* ── Left sidebar ── */

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #522653;
    flex-shrink: 0;
}

.sidebar-header {
    padding: 16px 16px 8px;
