    border: 1px solid #ddd;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.8rem;
    color: #616061;
}

.load-more-btn:hover:not(:disabled) {
    background: #eee;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    color: #888;
    font-size: 0.8rem;
